function normalizeAiMatchText(value) {
  return normalizeForSearch(value)
    .replace(/[^\w\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function mapDiseaseAiConfidenceLabel(confidence) {
  const numeric = Number(confidence);
  if (!Number.isFinite(numeric)) {
    return 'medium';
  }
  if (numeric >= 0.75) {
    return 'high';
  }
  if (numeric >= 0.45) {
    return 'medium';
  }
  return 'low';
}

function mapDiseaseAiConfidenceBadge(confidenceLabel) {
  if (confidenceLabel === 'high') {
    return 'wysoka';
  }
  if (confidenceLabel === 'low') {
    return 'niska';
  }
  return "średnia";
}

function buildDiseaseAiSuspectedDiseases({
  catalog = [],
  summary = '',
  hypotheses = [],
  description = '',
}) {
  const normalizedSummary = normalizeAiMatchText(
    [
      summary,
      description,
      ...(Array.isArray(hypotheses) ? hypotheses : []).map((entry) => entry?.label),
    ].join(' ')
  );
  const items = [];

  catalog.forEach((disease, index) => {
    const diseaseId = String(disease?.id ?? '').trim();
    const diseaseName = String(disease?.name ?? '').trim();
    if (!diseaseId || !diseaseName) {
      return;
    }
    const matchName = normalizeAiMatchText(diseaseName.split('(')[0] || diseaseName);
    if (!matchName) {
      return;
    }

    let score = 0;
    const matchedSignals = [];
    if (normalizedSummary.includes(matchName)) {
      score = Math.max(score, 0.68 - index * 0.01);
      matchedSignals.push(`nazwa "${diseaseName}" pojawia sie w analizie`);
    }

    const symptomLabels = normalizeArray(disease?.symptoms)
      .map((symptomId) => DISEASE_SYMPTOMS.find((entry) => entry.id === symptomId)?.label || symptomId)
      .map((label) => normalizeAiMatchText(label))
      .filter(Boolean);
    symptomLabels.forEach((symptomLabel) => {
      if (symptomLabel && normalizedSummary.includes(symptomLabel)) {
        score = Math.max(score, 0.42 + Math.min(0.22, matchedSignals.length * 0.04));
        matchedSignals.push(`pasuje objaw: ${symptomLabel}`);
      }
    });

    (Array.isArray(hypotheses) ? hypotheses : []).forEach((entry) => {
      const label = normalizeAiMatchText(entry?.label);
      if (label && (label.includes(matchName) || matchName.includes(label))) {
        const confidence = Number(entry?.confidence);
        if (Number.isFinite(confidence)) {
          score = Math.max(score, Math.min(0.95, Math.max(0.35, confidence)));
          matchedSignals.push('AI wskazalo podobna hipoteze');
        }
      }
    });

    if (score <= 0) {
      return;
    }

    const confidence = Math.round(score * 100) / 100;
    const confidenceLabel = mapDiseaseAiConfidenceLabel(confidence);
    items.push({
      diseaseId,
      label: diseaseName,
      confidence,
      confidenceLabel,
      reason:
        matchedSignals.length > 0
          ? `Najbardziej pasuje do katalogu: ${matchedSignals.slice(0, 2).join(', ')}.`
          : `Opis objawow jest zblizony do pozycji "${diseaseName}".`,
    });
  });

  const sorted = items.sort((a, b) => Number(b.confidence) - Number(a.confidence)).slice(0, 1);
  if (sorted.length > 0) {
    return sorted;
  }

  const fallbackDisease = normalizeArray(catalog).find(
    (disease) => String(disease?.id ?? '').trim() && String(disease?.name ?? '').trim()
  );
  if (!fallbackDisease) {
    return [];
  }

  return [
    {
      diseaseId: String(fallbackDisease.id),
      label: String(fallbackDisease.name),
      confidence: 0.25,
      confidenceLabel: 'low',
      reason:
        'To najblizsze wskazanie z katalogu przy bardzo ograniczonych danych. Potraktuj je jako punkt startowy do weryfikacji.',
    },
  ];
}

function buildPlantAiSuspectedIssues({
  catalog = [],
  summary = '',
  hypotheses = [],
}) {
  const normalizedSummary = normalizeAiMatchText(summary);
  const items = [];

  catalog.forEach((issue, index) => {
    const issueId = String(issue?.id ?? '').trim();
    const issueName = String(issue?.name ?? '').trim();
    if (!issueId || !issueName) {
      return;
    }
    const matchName = normalizeAiMatchText(issueName.split('(')[0] || issueName);
    if (!matchName) {
      return;
    }

    let score = 0;
    if (normalizedSummary.includes(matchName)) {
      score = Math.max(score, 0.66 - index * 0.01);
    }

    (Array.isArray(hypotheses) ? hypotheses : []).forEach((entry) => {
      const label = normalizeAiMatchText(entry?.label);
      if (label && (label.includes(matchName) || matchName.includes(label))) {
        const confidence = Number(entry?.confidence);
        if (Number.isFinite(confidence)) {
          score = Math.max(score, Math.min(0.95, Math.max(0.35, confidence)));
        }
      }
    });

    if (score <= 0) {
      return;
    }

    const confidence = Math.round(score * 100) / 100;
    const confidenceLabel = mapDiseaseAiConfidenceLabel(confidence);
    items.push({
      plantIssueId: issueId,
      label: issueName,
      confidence,
      confidenceLabel,
      reason: `Opis problemu jest zblizony do pozycji "${issueName}".`,
    });
  });

  const sorted = items.sort((a, b) => Number(b.confidence) - Number(a.confidence)).slice(0, 3);
  if (sorted.length > 0) {
    return sorted;
  }

  return [
    {
      plantIssueId: null,
      label: 'Niepewny problem',
      confidence: 0.32,
      confidenceLabel: 'low',
      reason: "Brak jednoznacznego dopasowania do katalogu problemów roślin.",
    },
  ];
}

