function buildMeasurementDetailRows(measurement, enabledTests = {}) {
  if (!measurement) {
    return [];
  }

  const rows = [
    enabledTests.ph ? { key: 'ph', label: 'pH', value: measurement.ph } : null,
    enabledTests.gh ? { key: 'gh', label: 'GH', value: measurement.gh } : null,
    enabledTests.kh ? { key: 'kh', label: 'KH', value: measurement.kh } : null,
    enabledTests.ph && enabledTests.kh
      ? {
          key: 'co2',
          label: 'CO2',
          value: getMeasurementNumericValue(measurement, 'co2'),
        }
      : null,
    enabledTests.ca ? { key: 'ca', label: 'Ca', value: measurement.ca } : null,
    enabledTests.mg ? { key: 'mg', label: 'Mg', value: measurement.mg } : null,
    enabledTests.k ? { key: 'k', label: 'K', value: measurement.k } : null,
    enabledTests.tds ? { key: 'tds', label: 'TDS', value: measurement.tds } : null,
    enabledTests.no2 ? { key: 'no2', label: 'NO2', value: measurement.no2 } : null,
    enabledTests.no3 ? { key: 'no3', label: 'NO3', value: measurement.no3 } : null,
    enabledTests.nh3nh4
      ? { key: 'nh3nh4', label: 'NH3/NH4', value: measurement.nh3nh4 }
      : null,
    enabledTests.po4 ? { key: 'po4', label: 'PO4', value: measurement.po4 } : null,
    enabledTests.fe ? { key: 'fe', label: 'Fe', value: measurement.fe } : null,
    enabledTests.temperature
      ? { key: 'temperature', label: 'Temp', value: measurement.temperature }
      : null,
  ];

  return rows.filter((item) => item && hasMeasurementDisplayValue(item.value));
}

const MEASUREMENT_VALUE_KEYS = [
  'ph',
  'gh',
  'kh',
  'ca',
  'mg',
  'k',
  'tds',
  'no2',
  'no3',
  'nh3nh4',
  'po4',
  'fe',
  'temperature',
];

function buildLatestMeasurementSnapshot(measurements = []) {
  if (!Array.isArray(measurements) || measurements.length === 0) {
    return null;
  }

  const latestMeasurement = measurements[0] ?? null;
  if (!latestMeasurement) {
    return null;
  }

  return { ...latestMeasurement };
}

function buildLatestMeasurementDisplaySnapshot(measurements = []) {
  if (!Array.isArray(measurements) || measurements.length === 0) {
    return null;
  }

  const latestMeasurement = measurements[0] ?? null;
  if (!latestMeasurement) {
    return null;
  }

  const snapshot = { ...latestMeasurement };

  MEASUREMENT_VALUE_KEYS.forEach((key) => {
    const hasCurrentValue = getMeasurementNumericValue(snapshot, key) !== null;
    if (hasCurrentValue) {
      return;
    }

    for (const measurement of measurements) {
      const fallbackValue = getMeasurementNumericValue(measurement, key);
      if (fallbackValue !== null) {
        snapshot[key] = fallbackValue;
        break;
      }
    }
  });

  return snapshot;
}

function buildLatestMeasurementValueSourceMsByKey(measurements = []) {
  const sourceMsByKey = new Map();

  if (!Array.isArray(measurements) || measurements.length === 0) {
    return sourceMsByKey;
  }

  MEASUREMENT_VALUE_KEYS.forEach((key) => {
    for (const measurement of measurements) {
      const value = getMeasurementNumericValue(measurement, key);
      if (value !== null) {
        sourceMsByKey.set(key, getMeasurementRecordedAtMs(measurement));
        break;
      }
    }
  });

  for (const measurement of measurements) {
    const directCo2 = Number(measurement?.co2);
    if (Number.isFinite(directCo2) && directCo2 > 0) {
      sourceMsByKey.set('co2', getMeasurementRecordedAtMs(measurement));
      break;
    }
  }

  if (!sourceMsByKey.has('co2')) {
    const phMs = Number(sourceMsByKey.get('ph') ?? 0);
    const khMs = Number(sourceMsByKey.get('kh') ?? 0);

    if (phMs && khMs) {
      sourceMsByKey.set('co2', Math.min(phMs, khMs));
    } else if (phMs || khMs) {
      sourceMsByKey.set('co2', phMs || khMs);
    }
  }

  return sourceMsByKey;
}

function getMeasurementKeysFromRecommendationParameter(parameter) {
  const normalized = String(parameter ?? '')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
  const keys = [];
  const push = (key) => {
    if (!keys.includes(key)) {
      keys.push(key);
    }
  };

  if (/\bph\b/.test(normalized)) push('ph');
  if (/\bgh\b/.test(normalized)) push('gh');
  if (/\bkh\b/.test(normalized)) push('kh');
  if (/\bca\b/.test(normalized)) push('ca');
  if (/\bmg\b/.test(normalized)) push('mg');
  if (/\btds\b/.test(normalized)) push('tds');
  if (/\bk\b/.test(normalized)) push('k');
  if (/\bno2\b/.test(normalized)) push('no2');
  if (/\bno3\b/.test(normalized)) push('no3');
  if (/nh3|nh4/.test(normalized)) push('nh3nh4');
  if (/\bpo4\b/.test(normalized)) push('po4');
  if (/\bfe\b/.test(normalized)) push('fe');
  if (/\bco2\b/.test(normalized)) push('co2');
  if (normalized.includes('temp')) push('temperature');
  if (normalized.includes('temperat')) push('temperature');
  if (normalized.includes('azotyn')) push('no2');
  if (normalized.includes('azotan')) push('no3');
  if (normalized.includes('amoniak')) push('nh3nh4');
  if (normalized.includes('fosforan')) push('po4');
  if (normalized.includes('zelazo')) push('fe');
  if (normalized.includes('potas')) push('k');
  if (normalized.includes('przewodnosc')) push('tds');
  if (normalized.includes('twardosc ogolna')) push('gh');
  if (normalized.includes('twardosc weglanowa')) push('kh');
  if (normalized.includes('grzalk')) push('temperature');
  if (normalized.includes('temperatura')) push('temperature');

  return keys;
}

function getMeasurementSeverityFromValue(key, rawValue) {
  const normalizedRawValue =
    typeof rawValue === 'string' ? rawValue.trim().replace(',', '.') : rawValue;
  const value = Number(normalizedRawValue);

  if (!Number.isFinite(value)) {
    return 'ok';
  }

  if (key === 'ph') {
    if (value < 5.8 || value > 8.5) return 'critical';
    if (value < 6.5 || value > 7.8) return 'warning';
    return 'ok';
  }

  if (key === 'gh') {
    if (value < 3 || value > 22) return 'critical';
    if (value < 5 || value > 14) return 'warning';
    return 'ok';
  }

  if (key === 'kh') {
    if (value < 1 || value > 14) return 'critical';
    if (value < 3 || value > 8) return 'warning';
    return 'ok';
  }

  if (key === 'ca') {
    if (value < 10 || value > 100) return 'critical';
    if (value < 20 || value > 60) return 'warning';
    return 'ok';
  }

  if (key === 'mg') {
    if (value < 2 || value > 35) return 'critical';
    if (value < 5 || value > 20) return 'warning';
    return 'ok';
  }

  if (key === 'k') {
    if (value < 2 || value > 40) return 'critical';
    if (value < 5 || value > 30) return 'warning';
    return 'ok';
  }

  if (key === 'tds') {
    if (value < 40 || value > 600) return 'critical';
    if (value < 80 || value > 450) return 'warning';
    return 'ok';
  }

  if (key === 'no2') {
    if (value > 0) return 'critical';
    return 'ok';
  }

  if (key === 'no3') {
    if (value > 80) return 'critical';
    if (value > 25) return 'warning';
    return 'ok';
  }

  if (key === 'nh3nh4') {
    if (value > 0.2) return 'critical';
    if (value > 0.05) return 'warning';
    return 'ok';
  }

  if (key === 'po4') {
    if (value > 2) return 'critical';
    if (value > 1) return 'warning';
    return 'ok';
  }

  if (key === 'fe') {
    if (value > 0.5) return 'critical';
    if (value > 0.2) return 'warning';
    return 'ok';
  }

  if (key === 'co2') {
    if (value > 40) return 'critical';
    if (value < 10 || value > 30) return 'warning';
    return 'ok';
  }

  if (key === 'temperature') {
    if (value < 22 || value > 29) return 'critical';
    if (value < 24 || value > 27) return 'warning';
    return 'ok';
  }

  return 'ok';
}

function getMeasurementSeverityFromValueWithTargetRanges(
  key,
  rawValue,
  targetRanges = null
) {
  const normalizedRawValue =
    typeof rawValue === 'string' ? rawValue.trim().replace(',', '.') : rawValue;
  const value = Number(normalizedRawValue);

  if (!Number.isFinite(value)) {
    return 'ok';
  }

  if (!targetRanges || typeof targetRanges !== 'object') {
    return getMeasurementSeverityFromValue(key, value);
  }

  const range = targetRanges?.[key];
  const min = Number(range?.min);
  const max = Number(range?.max);

  if (!Number.isFinite(min) || !Number.isFinite(max) || min > max) {
    return getMeasurementSeverityFromValue(key, value);
  }

  const span = Math.max((max - min) * 0.35, 0.1);
  const criticalMin = min - span;
  const criticalMax = max + span;

  if (value < criticalMin || value > criticalMax) {
    return 'critical';
  }

  if (value < min || value > max) {
    return 'warning';
  }

  return 'ok';
}

function getMeasurementTargetRangeLabel(key) {
  if (key === 'ph') return '6.5-7.8';
  if (key === 'gh') return '5-14 dGH';
  if (key === 'kh') return '3-8 dKH';
  if (key === 'ca') return '20-60 mg/l';
  if (key === 'mg') return '5-20 mg/l';
  if (key === 'k') return '5-30 mg/l';
  if (key === 'tds') return '80-450 ppm';
  if (key === 'no2') return '0 mg/l';
  if (key === 'no3') return '5-25 mg/l';
  if (key === 'nh3nh4') return '<= 0.05 mg/l';
  if (key === 'po4') return '0.1-1.0 mg/l';
  if (key === 'fe') return '0.02-0.2 mg/l';
  if (key === 'co2') return '10-30 mg/l';
  if (key === 'temperature') return '24-27 C';
  return '-';
}

function getMeasurementCustomTargetRangeLabel(key, targetRanges = null) {
  if (!targetRanges || typeof targetRanges !== 'object') {
    return getMeasurementTargetRangeLabel(key);
  }

  const range = targetRanges?.[key];
  const min = Number(range?.min);
  const max = Number(range?.max);
  if (!Number.isFinite(min) || !Number.isFinite(max) || min > max) {
    return getMeasurementTargetRangeLabel(key);
  }

  const unitByKey = {
    gh: 'dGH',
    kh: 'dKH',
    ca: 'mg/l',
    mg: 'mg/l',
    k: 'mg/l',
    tds: 'ppm',
    no2: 'mg/l',
    no3: 'mg/l',
    nh3nh4: 'mg/l',
    po4: 'mg/l',
    fe: 'mg/l',
    co2: 'mg/l',
    temperature: 'C',
  };
  const unit = unitByKey[key] ?? '';
  return unit ? `${min}-${max} ${unit}` : `${min}-${max}`;
}

function buildMeasurementIssueSeverityMapFromAnalysis(analysis, rows = []) {
  const map = new Map();
  const setSeverity = (key, severity) => {
    if (!key || !severity || severity === 'ok') {
      return;
    }

    const existingSeverity = map.get(key);
    if (
      !existingSeverity ||
      getAnalysisSeverityRank(severity) > getAnalysisSeverityRank(existingSeverity)
    ) {
      map.set(key, severity);
    }
  };

  (analysis?.recommendations ?? []).forEach((recommendation) => {
    const severity = recommendation?.severity;
    const keys = getMeasurementKeysFromRecommendationParameter(
      recommendation?.parameter
    );

    keys.forEach((key) => setSeverity(key, severity));
  });

  rows.forEach((row) => {
    const rowKey = String(row?.key ?? '');
    if (!rowKey || map.has(rowKey)) {
      return;
    }
    map.set(rowKey, 'ok');
  });

  return map;
}

function getMeasurementDefaultAction(key, severity) {
  if (severity === 'ok') {
    return 'Wynik jest w bezpiecznym zakresie. Kontynuuj obecna pielegnacje i regularne pomiary.';
  }

  if (key === 'no2') {
    return "Podmien wodę od razu, mocno napowietrz i sprawdź filtr biologiczny.";
  }

  if (key === 'no3') {
    return "Wykonaj podmianę wody i ogranicz karmienie, a dodatkowo zwiększ mase roślin szybko rosnacych.";
  }

  if (key === 'temperature') {
    return "Skoryguj ustawieńia grzałki/chlodzenia stopniowo i obserwuj reakcje ryb.";
  }

  if (key === 'co2') {
    return 'Skoryguj dozowanie CO2 i utrzymuj stabilny poziom przez kolejne dni.';
  }

  if (key === 'k') {
    return "Skoryguj nawożenie potasem i monitoruj proporcje K:Ca:Mg przy kolejnych pomiarach.";
  }

  if (key === 'tds') {
    return "Dostosuj mineralizacje i podmiany, aby wróic do stabilnego zakresu TDS.";
  }

  return severity === 'critical'
    ? "Wprowadź korekte jeszcze dzisiaj i powtorz pomiar po zmianach."
    : "Zaplanow korekte przy najbliższej pielegnacji i kontrolny pomiar.";
}

function getMeasurementDefaultImpact(key, severity) {
  if (severity === 'ok') {
    return "Przy utrzymaniu tego poziomu parametr nie powinien teraz zwiększac ryzyka dla obsady.";
  }

  if (key === 'no2') {
    return "Podwyzszone NO2 szybko podnosi stres i może prowadzic do zatruc.";
  }

  if (key === 'no3') {
    return "Wysokie NO3 zwiększa ryzyko glonów, oslabienia ryb i gorszego samopoczucia obsady.";
  }

  if (key === 'nh3nh4') {
    return "Podwyzszone NH3/NH4 zwiększa ryzyko podtrucia i problemów z oddychaniem u ryb.";
  }

  if (key === 'temperature') {
    return "Niestabilna temperatura nasila stres i może oslabic odporność ryb.";
  }

  if (key === 'ph') {
    return "Odchylenie pH może zwiększac stres i podatnosc na infekcje.";
  }

  return severity === 'critical'
    ? "Bez korekty może dojsc do pogorszenia kondycji zbiornika i obsady."
    : "Bez korekty może stopniowo obniżac komfort zycia ryb i roślin.";
}

