function normalizeText(value) {
  return normalizeForSearch(value)
    .replace(/[^a-zA-Z0-9 .-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeLatinCatalogKey(value) {
  const normalized = String(value ?? '')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-zA-Z0-9.\s-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();

  if (!normalized) {
    return '';
  }

  const tokens = normalized.split(' ').filter(Boolean);

  if (tokens.length >= 2) {
    const genus = tokens[0];
    const rank = tokens[1].replace(/\./g, '');

    if (rank === 'spp' || rank === 'sp') {
      return `${genus} spp`;
    }
  }

  return normalized
    .replace(/\bsp\.\b/g, 'sp')
    .replace(/\bspp\.\b/g, 'spp');
}

function normalizeSubstrateType(value) {
  return String(value ?? '').trim().toLowerCase();
}

function normalizeSubstrateTypes(value) {
  if (Array.isArray(value)) {
    const normalized = value
      .map((item) => normalizeSubstrateType(item))
      .filter((item) => SUBSTRATE_OPTIONS.some((option) => option.value === item));
    return [...new Set(normalized)];
  }

  const single = normalizeSubstrateType(value);
  return SUBSTRATE_OPTIONS.some((option) => option.value === single) ? [single] : [];
}

function normalizeLightIntensity(value) {
  return String(value ?? '').trim().toLowerCase();
}

function normalizeLightModelId(value) {
  return String(value ?? '').trim().toLowerCase();
}

function getLightLampById(lightModelId) {
  const normalized = normalizeLightModelId(lightModelId);
  if (!normalized) {
    return null;
  }
  return runtimeLightLampCatalog.find((item) => item.id === normalized) ?? null;
}

function estimateLightIntensityFromLumens(lightLumens, liters) {
  const normalizedLumens = Number(lightLumens);
  const normalizedLiters = Number(liters);
  if (
    !Number.isFinite(normalizedLumens) ||
    normalizedLumens <= 0 ||
    !Number.isFinite(normalizedLiters) ||
    normalizedLiters <= 0
  ) {
    return '';
  }

  const lumensPerLiter = normalizedLumens / normalizedLiters;
  if (lumensPerLiter < 20) {
    return 'low';
  }
  if (lumensPerLiter <= 40) {
    return 'medium';
  }
  return 'high';
}

function getTankLightingSummary(tank) {
  const lightHours = Number(tank?.lightHours);
  const lightModelId = normalizeLightModelId(tank?.lightModelId);
  const catalogLamp = getLightLampById(lightModelId);
  const customLampName = String(tank?.lightModelName ?? '').trim();
  const rawLightLumens = Number(tank?.lightLumens);
  const lightLumens = Number.isFinite(rawLightLumens) && rawLightLumens > 0
    ? rawLightLumens
    : Number(catalogLamp?.lumens);
  const liters = Number(tank?.liters);
  const lumensPerLiter =
    Number.isFinite(lightLumens) &&
    lightLumens > 0 &&
    Number.isFinite(liters) &&
    liters > 0
      ? lightLumens / liters
      : null;
  const derivedIntensity = estimateLightIntensityFromLumens(lightLumens, liters);
  const hasLamp =
    Boolean(lightModelId) ||
    (Number.isFinite(lightLumens) && lightLumens > 0);

  return {
    lightModelId,
    lightModelName: customLampName || catalogLamp?.name || '',
    lightLumens: Number.isFinite(lightLumens) && lightLumens > 0 ? lightLumens : null,
    lumensPerLiter: Number.isFinite(lumensPerLiter) ? lumensPerLiter : null,
    lightIntensity: hasLamp
      ? derivedIntensity || normalizeLightIntensity(tank?.lightIntensity) || 'low'
      : 'low',
    lightHours: Number.isFinite(lightHours) ? lightHours : null,
    isDaylightOnly: !hasLamp,
  };
}

function normalizeAquariumType(value) {
  const normalized = String(value ?? '').trim().toLowerCase();
  const extendedAllowed = new Set([
    'plant',
    'shrimp',
    'mixed',
    'general',
    'planted_low_tech',
    'planted_high_tech',
    'malawi',
    'tanganyika',
    'betta_or_calm_fish',
  ]);
  if (AQUARIUM_TYPE_OPTIONS.some((item) => item.value === normalized)) {
    return normalized;
  }
  return extendedAllowed.has(normalized) ? normalized : '';
}

function normalizeOnboardingMode(value) {
  const normalized = String(value ?? '').trim().toLowerCase();
  if (normalized === 'existing_running') {
    return 'mature_media_start';
  }
  const allowedModes = new Set([
    'fresh_start',
    'restart',
    'mature_media_start',
  ]);
  return allowedModes.has(normalized) ? normalized : 'fresh_start';
}

function normalizeAddTankStartType(value) {
  const normalized = String(value ?? '').trim().toLowerCase();
  const allowed = new Set(ADD_TANK_START_OPTIONS.map((item) => item.value));
  return allowed.has(normalized) ? normalized : 'new_from_scratch';
}

function onboardingModeFromStartType(startType) {
  const normalized = normalizeAddTankStartType(startType);
  if (normalized === 'restart_or_transfer') {
    return 'restart';
  }
  if (normalized === 'mature_existing' || normalized === 'based_on_existing') {
    return 'mature_media_start';
  }
  return 'fresh_start';
}

function mapWizardProfileToModel(profile) {
  const normalized = String(profile ?? '').trim().toLowerCase();
  if (normalized === 'planted_low_tech') {
    return { aquariumType: 'planted_low_tech', waterProfile: 'low_tech' };
  }
  if (normalized === 'planted_high_tech') {
    return { aquariumType: 'planted_high_tech', waterProfile: 'high_tech' };
  }
  if (normalized === 'shrimp') {
    return { aquariumType: 'shrimp', waterProfile: 'shrimp' };
  }
  if (normalized === 'species_only') {
    return { aquariumType: 'general', waterProfile: 'single_species' };
  }
  if (normalized === 'malawi') {
    return { aquariumType: 'malawi', waterProfile: 'malawi' };
  }
  if (normalized === 'tanganyika') {
    return { aquariumType: 'tanganyika', waterProfile: 'tanganyika' };
  }
  if (normalized === 'biotope') {
    return { aquariumType: 'general', waterProfile: 'general' };
  }
  if (normalized === 'custom') {
    return { aquariumType: 'general', waterProfile: 'general' };
  }
  return { aquariumType: 'general', waterProfile: 'general' };
}

function deriveWizardProfileFromTank(tank) {
  const aquariumType = normalizeAquariumType(tank?.aquariumType);
  const waterProfile = normalizeWaterProfile(
    tank?.waterProfile ?? getDefaultWaterProfileForAquariumType(aquariumType)
  );
  if (waterProfile === 'single_species') {
    return 'species_only';
  }
  if (aquariumType === 'planted_high_tech' || waterProfile === 'high_tech') {
    return 'planted_high_tech';
  }
  if (aquariumType === 'planted_low_tech' || waterProfile === 'low_tech') {
    return 'planted_low_tech';
  }
  if (aquariumType === 'shrimp' || waterProfile === 'shrimp') {
    return 'shrimp';
  }
  if (aquariumType === 'malawi' || waterProfile === 'malawi') {
    return 'malawi';
  }
  if (aquariumType === 'tanganyika' || waterProfile === 'tanganyika') {
    return 'tanganyika';
  }
  return 'general';
}

