function getDefaultWaterProfileForAquariumType(aquariumType) {
  const normalizedType = normalizeAquariumType(aquariumType);
  if (normalizedType === 'plant') {
    return 'plant';
  }
  if (normalizedType === 'shrimp') {
    return 'shrimp';
  }
  return DEFAULT_WATER_PROFILE;
}

function getWaterTargetDefaults(profile) {
  const normalizedProfile = normalizeWaterProfile(profile);
  const source =
    WATER_TARGET_DEFAULTS_BY_PROFILE[normalizedProfile] ??
    WATER_TARGET_DEFAULTS_BY_PROFILE[DEFAULT_WATER_PROFILE];

  const next = {};
  WATER_TARGET_FIELDS.forEach((field) => {
    const raw =
      source[field.key] ?? WATER_TARGET_DEFAULTS_BY_PROFILE[DEFAULT_WATER_PROFILE][field.key];
    next[field.key] = {
      min: Number(raw.min),
      max: Number(raw.max),
    };
  });

  return next;
}

function getFishCatalogDisplayLabel(fish) {
  const commonName = String(fish?.commonName ?? fish?.name ?? '').trim();
  const latinName = String(fish?.latinName ?? '').trim();

  if (commonName && latinName) {
    return `${commonName} (${latinName})`;
  }

  return commonName || latinName || 'Wybrany gatunek';
}

function buildSingleSpeciesTargetRangesFromFish(
  fish,
  fallbackProfile = DEFAULT_WATER_PROFILE
) {
  const base = getWaterTargetDefaults(fallbackProfile);
  if (!fish) {
    return base;
  }

  const next = { ...base };
  const applyRange = (key, minRaw, maxRaw) => {
    const min = Number(minRaw);
    const max = Number(maxRaw);

    if (!Number.isFinite(min) || !Number.isFinite(max) || min > max) {
      return;
    }

    next[key] = { min, max };
  };

  applyRange('ph', fish.phMin, fish.phMax);
  applyRange('gh', fish.ghMin, fish.ghMax);
  applyRange('temperature', fish.tempMin, fish.tempMax);

  return next;
}

function normalizeTankTargetRanges(value, profile = DEFAULT_WATER_PROFILE) {
  return normalizeTankTargetRangesService(value, profile, {
    getWaterTargetDefaults,
    WATER_TARGET_FIELDS,
  });
}

