  const handleRefresh = useCallback(async () => {
    if (!user?.uid || refreshing) {
      return;
    }

    setRefreshing(true);

    try {
      const preferredTankId = selectedTank?.id ?? undefined;

      await Promise.all([fetchFishCatalog(), fetchPlantCatalog(), fetchHomeData(user.uid)]);
      await fetchTanks(user.uid, preferredTankId);

      if (preferredTankId) {
        await Promise.all([
          fetchMeasurements(user.uid, preferredTankId),
          fetchStockItems(user.uid, preferredTankId),
          fetchTankDiseaseCases(user.uid, preferredTankId),
        ]);
      }
    } catch (error) {
      alert(
        "Błąd odświeżania danych: " +
          (error instanceof Error ? error.message : '')
      );
    } finally {
      setRefreshing(false);
    }
  }, [
    user?.uid,
    refreshing,
    selectedTank?.id,
    fetchFishCatalog,
    fetchPlantCatalog,
    fetchHomeData,
    fetchTanks,
    fetchMeasurements,
    fetchStockItems,
    fetchTankDiseaseCases,
  ]);

  const handleAuthSubmit = async () => {
    if (authBusy) {
      return;
    }

    const normalizedEmail = email.trim();
    const normalizedNickname = authNickname.trim();

    if (!normalizedEmail || !password) {
      alert('Podaj email i haslo');
      return;
    }

    if (authMode === 'register' && !normalizedNickname) {
      alert('Podaj imie lub nick');
      return;
    }

    setAuthBusy(true);

    try {
      if (authMode === 'register') {
        skipNextUnverifiedAlertRef.current = true;
        const credentials = await createUserWithEmailAndPassword(
          auth,
          normalizedEmail,
          password
        );

        await updateProfile(credentials.user, {
          displayName: normalizedNickname,
        });
        await sendEmailVerification(credentials.user);
        await signOut(auth);

        setAuthNickname('');
        setPassword('');
        setAuthMode('login');
        alert(
          "Konto utworzone. Wysłaliśmy link weryfikacyjny na email. Zweryfikuj adres i zaloguj się ponownie."
        );
      } else {
        const credentials = await signInWithEmailAndPassword(
          auth,
          normalizedEmail,
          password
        );
        await credentials.user.reload();
        const refreshedUser = auth.currentUser ?? credentials.user;

        if (!refreshedUser.emailVerified) {
          try {
            await sendEmailVerification(refreshedUser);
          } catch (verificationError) {
            console.warn(
              "Błąd ponownej wysylki weryfikacji email:",
              verificationError instanceof Error
                ? verificationError.message
                : String(verificationError)
            );
          }

          skipNextUnverifiedAlertRef.current = true;
          await signOut(auth);
          showUnverifiedEmailAlert(
            "Najpierw zweryfikuj email. Wysłaliśmy ponownie link aktywacyjny."
          );
          return;
        }
      }
    } catch (error) {
      skipNextUnverifiedAlertRef.current = false;
      alert(
        `${authMode === 'register' ? "Błąd rejestracji" : "Błąd logowania"}: ` +
          (error instanceof Error ? error.message : '')
      );
    } finally {
      setAuthBusy(false);
    }
  };

  const completeGoogleAuthWithTokens = useCallback(
    async ({ idToken, accessToken }, isDeleteAccountGoogleReauth) => {
      try {
        const credential = GoogleAuthProvider.credential(
          idToken || null,
          accessToken || null
        );
        if (isDeleteAccountGoogleReauth) {
          const currentAuthUser = auth.currentUser;
          if (!currentAuthUser) {
            throw new Error(t('deleteAccountReauthSessionMissing'));
          }

          await reauthenticateWithCredential(currentAuthUser, credential);
          setDeleteAccountReauthPassword('');
          setIsDeleteAccountReauthModalVisible(false);
          await deleteAccountConfirmedRef.current?.(false);
        } else {
          await signInWithCredential(auth, credential);
        }
      } catch (error) {
        if (isDeleteAccountGoogleReauth) {
          alert(
            t('deleteAccountReauthGoogleError', {
              value: error instanceof Error ? error.message : String(error ?? ''),
            })
          );
        } else {
          alert(
            "Błąd logowania Google: " +
              (error instanceof Error ? error.message : '')
          );
        }
      } finally {
        if (isDeleteAccountGoogleReauth) {
          setDeleteAccountReauthBusy(false);
        } else {
          setAuthBusy(false);
        }
      }
    },
    [t]
  );
  const getGoogleAuthTokens = useCallback((result) => {
    const idToken =
      result?.authentication?.idToken ?? result?.params?.id_token ?? '';
    const accessToken =
      result?.authentication?.accessToken ?? result?.params?.access_token ?? '';

    return {
      idToken,
      accessToken,
      hasToken: Boolean(idToken || accessToken),
      hasCode: Boolean(result?.params?.code),
    };
  }, []);

  useEffect(() => {
    if (!pendingGoogleAuthIntent || !googleAuthResponse) {
      return;
    }

    const isDeleteAccountGoogleReauth =
      pendingGoogleAuthIntent === 'reauth-delete-account';

    if (googleAuthResponse.type !== 'success') {
      setPendingGoogleAuthIntent(null);
      if (isDeleteAccountGoogleReauth) {
        setDeleteAccountReauthBusy(false);
      } else {
        setAuthBusy(false);
      }
      return;
    }

    const { idToken, accessToken, hasToken, hasCode } =
      getGoogleAuthTokens(googleAuthResponse);

    if (hasToken) {
      setPendingGoogleAuthIntent(null);
      completeGoogleAuthWithTokens(
        { idToken, accessToken },
        isDeleteAccountGoogleReauth
      );
      return;
    }

    if (hasCode) {
      return;
    }

    setPendingGoogleAuthIntent(null);
    if (isDeleteAccountGoogleReauth) {
      setDeleteAccountReauthBusy(false);
    } else {
      setAuthBusy(false);
    }
    alert(
      "Logowanie Google wróciło do aplikacji, ale Google nie przekazał tokenu. Spróbuj ponownie za chwilę."
    );
  }, [
    completeGoogleAuthWithTokens,
    getGoogleAuthTokens,
    googleAuthResponse,
    pendingGoogleAuthIntent,
  ]);

  const handleGoogleAuth = async (intent = 'sign-in') => {
    const isDeleteAccountGoogleReauth = intent === 'reauth-delete-account';
    if (isDeleteAccountGoogleReauth) {
      if (deleteAccountReauthBusy || deleteAccountBusy) {
        return;
      }
    } else if (authBusy) {
      return;
    }

    if (IS_EXPO_GO) {
      alert(
        "Logowanie Google nie dziala poprawnie w Expo Go. Uruchom aplikacje w development build (dev client), wtedy Google OAuth będzie zgodny z polityka Google."
      );
      return;
    }

    if (!isGoogleAuthConfiguredForPlatform) {
      const expectedEnvKey = Platform.select({
        ios: 'EXPO_PUBLIC_GOOGLE_IOS_CLIENT_ID',
        android: 'EXPO_PUBLIC_GOOGLE_ANDROID_CLIENT_ID',
        default: 'EXPO_PUBLIC_GOOGLE_WEB_CLIENT_ID',
      });
      alert(
        `Logowanie Google nie jest skonfigurowane. Uzupelnij ${expectedEnvKey} i uruchom aplikacje ponownie.`
      );
      return;
    }

    if (!googleAuthRequest) {
      alert(
        "Logowanie Google nie jest jeszcze gotowe. Sprawdź konfiguracje client ID."
      );
      return;
    }

    if (isDeleteAccountGoogleReauth) {
      setDeleteAccountReauthBusy(true);
    } else {
      setAuthBusy(true);
    }
    setPendingGoogleAuthIntent(intent);

    try {
      const result = await promptGoogleAuthAsync();
      if (result.type !== 'success') {
        setPendingGoogleAuthIntent(null);
        if (isDeleteAccountGoogleReauth) {
          setDeleteAccountReauthBusy(false);
        } else {
          setAuthBusy(false);
        }
        return;
      }

      const { idToken, accessToken, hasToken, hasCode } =
        getGoogleAuthTokens(result);

      if (!hasToken && hasCode) {
        return;
      }

      if (!hasToken) {
        setPendingGoogleAuthIntent(null);
        if (isDeleteAccountGoogleReauth) {
          setDeleteAccountReauthBusy(false);
        } else {
          setAuthBusy(false);
        }
        alert(
          "Logowanie Google nie zwróciło tokenu. Sprawdź konfigurację OAuth i spróbuj ponownie."
        );
        return;
      }

      setPendingGoogleAuthIntent(null);
      await completeGoogleAuthWithTokens(
        { idToken, accessToken },
        isDeleteAccountGoogleReauth
      );
    } catch (error) {
      setPendingGoogleAuthIntent(null);
      if (isDeleteAccountGoogleReauth) {
        setDeleteAccountReauthBusy(false);
      } else {
        setAuthBusy(false);
      }
      alert(
        isDeleteAccountGoogleReauth
          ? t('deleteAccountReauthGoogleStartError', {
              value: error instanceof Error ? error.message : String(error ?? ''),
            })
          : "Błąd uruchamiania logowania Google: " +
            (error instanceof Error ? error.message : '')
      );
    }
  };

