  const handleSaveMeasurement = async () => {
    if (!user || saveBusy) {
      return;
    }

    if (!selectedTank?.id) {
      alert('Najpierw dodaj i wybierz aktywne akwarium');
      return;
    }
    if (selectedTankLockedByPlan) {
      alert('To akwarium jest w trybie tylko do odczytu w obecnym planie.');
      return;
    }

    Keyboard.dismiss();
    setSaveBusy(true);

    try {
      const note = measurementNote.trim();
      const selectedTests = availableMeasurementTests;
      const measuredAt = parseMeasurementDateInputOrThrow(measurementDateInput);

      if (measurementInputRows.length === 0) {
        throw new Error(
          "W ustawieniach włącz przynajmniej 1 pole, aby pokazac je w formularzu."
        );
      }

      const measurement = { note, measuredAt };

      measurementInputRows.forEach((field) => {
        const parsedValue = field.parseValue(field.value);

        if (parsedValue === null) {
          return;
        }

        measurement[field.key] = parsedValue;
      });

      const co2Estimated = calculateCo2FromKhPhLogic(measurement.kh, measurement.ph);
      if (co2Estimated !== null) {
        measurement.co2 = co2Estimated;
      }

      const normalizedMeasurement = normalizeMeasurementRuntime(measurement);
      const measurementValidation = validateMeasurementModelRuntime(
        normalizedMeasurement
      );
      if (!measurementValidation.ok) {
        console.warn(
          '[measurementModel] validation issues:',
          measurementValidation.issues
        );
      }

      const baseAnalysis = analyzeMeasurementLogic(
        normalizedMeasurement,
        selectedTests,
        selectedTankWaterAnalysisOptions
      );
      const contextInsights = buildContextualEcosystemInsights({
        measurement: normalizedMeasurement,
        enabledTests: selectedTests,
        stockItems,
        tank: selectedTank,
        equipmentAssessment: buildTankEquipmentAssessment(
          selectedTank,
          equipmentCatalogForAnalysis
        ),
        targetRanges: selectedTankWaterAnalysisOptions?.targetRanges,
      });
      const analysis = mergeWaterAnalysisWithContext(baseAnalysis, contextInsights);

      if (editingMeasurementId) {
        const currentMeasurementItem =
          measurements.find((item) => item.id === editingMeasurementId) ?? null;
        await updateDocWithTelemetry(
          'measurements',
          doc(db, 'measurements', editingMeasurementId),
          {
            ...buildMeasurementRuleSanitizationPatch(currentMeasurementItem),
            ...normalizedMeasurement,
            updatedAt: new Date(),
          },
          {
            userId: user.uid,
            tankId: selectedTank.id,
            source: 'save_measurement_update',
          }
        );
      } else {
        await addDocWithTelemetry(
          'measurements',
          collection(db, 'measurements'),
          {
            userId: user.uid,
            tankId: selectedTank.id,
            tankName: selectedTank.name,
            createdAt: new Date(),
            ...normalizedMeasurement,
          },
          {
            userId: user.uid,
            tankId: selectedTank.id,
            source: 'save_measurement_create',
          }
        );
      }

      resetMeasurementDraft();
      setSelectedMeasurementId(null);
      setEditingMeasurementId(null);
      setIsAddMeasurementModalVisible(false);

      await fetchMeasurements(user.uid, selectedTank.id);
      await fetchHomeData(user.uid);

      if (!hasParameterAnalysisAccess) {
        alert(
          editingMeasurementId
            ? `Zaktualizowano wpis dla akwarium: ${selectedTank.name}.`
            : `Zapisano dla akwarium: ${selectedTank.name}.`
        );
      } else if (!analysis || analysis.recommendations.length === 0) {
        alert(
          `${
            editingMeasurementId
              ? `Zaktualizowano wpis dla akwarium: ${selectedTank.name}.`
              : `Zapisano dla akwarium: ${selectedTank.name}.`
          }\n\nParametry są w normie.`
        );
      } else {
        const highlights = analysis.recommendations
          .slice(0, 3)
          .map((item) => `- ${item.parameter}: ${item.issue}`)
          .join('\n');
        alert(
          `${
            editingMeasurementId
              ? `Zaktualizowano wpis dla akwarium: ${selectedTank.name}.`
              : `Zapisano dla akwarium: ${selectedTank.name}.`
          }\n\n${analysis.summary}\n${highlights}`
        );
      }
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "nieznany błąd";
      alert("Błąd: " + message);
    } finally {
      setSaveBusy(false);
    }
  };

  const handleDeleteMeasurement = (measurementId) => {
    if (!user?.uid || !selectedTank?.id || !measurementId || measurementDeleteBusy) {
      return;
    }
    if (selectedTankLockedByPlan) {
      alert('To akwarium jest w trybie tylko do odczytu w obecnym planie.');
      return;
    }

    Alert.alert(
      "Usuń wpis z historii",
      "Czy na pewno chcesz usuńąć ten wpis pomiaru? Tej operacji nie da się cofnąć (nieodwracalne).",
      [
        { text: 'Anuluj', style: 'cancel' },
        {
          text: "Usuń",
          style: 'destructive',
          onPress: async () => {
            if (!user?.uid || !selectedTank?.id || measurementDeleteBusy) {
              return;
            }

            setMeasurementDeleteBusy(true);

            try {
              await deleteDoc(doc(db, 'measurements', measurementId));

              if (selectedMeasurementId === measurementId) {
                setSelectedMeasurementId(null);
              }
              if (editingMeasurementId === measurementId) {
                setEditingMeasurementId(null);
              }

              await fetchMeasurements(user.uid, selectedTank.id);
              await fetchHomeData(user.uid);
              alert("Wpis z historii został usunięty.");
            } catch (error) {
              alert(
                "Błąd usuwania wpisu z historii: " +
                  (error instanceof Error ? error.message : '')
              );
            } finally {
              setMeasurementDeleteBusy(false);
            }
          },
        },
      ]
    );
  };

  const handleDeleteIssueHistoryEntry = (issueEntry) => {
    const issueId = String(issueEntry?.id ?? '');
    if (
      !issueId ||
      !user?.uid ||
      !selectedTank?.id ||
      Boolean(historyIssueDeleteBusyId)
    ) {
      return;
    }

    const issueName = String(issueEntry?.issueName ?? t('noData')).trim();
    Alert.alert(
      "Usuń wpis z historii problemów",
      `Czy na pewno chcesz usuńąć "${issueName}"? Tej operacji nie da się cofnąć (nieodwracalne).`,
      [
        { text: 'Anuluj', style: 'cancel' },
        {
          text: "Usuń",
          style: 'destructive',
          onPress: async () => {
            if (
              !issueId ||
              !user?.uid ||
              !selectedTank?.id ||
              Boolean(historyIssueDeleteBusyId)
            ) {
              return;
            }

            setHistoryIssueDeleteBusyId(issueId);
            try {
              await deleteDoc(doc(db, 'tankDiseaseCases', issueId));
              await fetchTankDiseaseCases(user.uid, selectedTank.id);
              await fetchHomeData(user.uid);
              setExpandedHistoryIssueId((prev) => (prev === issueId ? null : prev));
              alert("Wpis z historii problemów został usunięty.");
            } catch (error) {
              alert(
                "Błąd usuwania wpisu z historii problemów: " +
                  (error instanceof Error ? error.message : '')
              );
            } finally {
              setHistoryIssueDeleteBusyId(null);
            }
          },
        },
      ]
    );
  };

  const handleToggleOnboardingTaskCheck = async (rowId, checked) => {
    if (
      !rowId ||
      !user?.uid ||
      !selectedTank?.id ||
      onboardingTaskBusy ||
      !hasTaskChecklistAccess
    ) {
      return;
    }

    const currentChecks = normalizeOnboardingTaskChecks(selectedTank.onboardingTaskChecks);
    const nextChecks = {
      ...currentChecks,
      [rowId]: Boolean(checked),
    };

    setOnboardingTaskBusy(true);
    try {
      await updateDocWithTelemetry(
        'tanks',
        doc(db, 'tanks', selectedTank.id),
        buildTankUpdatePayload(selectedTank, {
          onboardingTaskChecks: nextChecks,
        }),
        {
          userId: user.uid,
          tankId: selectedTank.id,
          source: 'toggle_onboarding_task_check',
        }
      );

      setTanks((prev) =>
        prev.map((tank) =>
          tank.id === selectedTank.id ? { ...tank, onboardingTaskChecks: nextChecks } : tank
        )
      );
      setSelectedTank({
        ...selectedTank,
        onboardingTaskChecks: nextChecks,
      });
    } catch (error) {
      alert(
        "Błąd zapisu statusu zadania onboardingu: " +
          (error instanceof Error ? error.message : '')
      );
    } finally {
      setOnboardingTaskBusy(false);
    }
  };

  const handleSetTankOnboardingEnabled = async (enabled) => {
    if (!selectedTank?.id || !user?.uid || onboardingToggleBusy) {
      return;
    }
    if (selectedTankLockedByPlan) {
      alert('To akwarium jest w trybie tylko do odczytu w obecnym planie.');
      return;
    }

    const nextEnabled = Boolean(enabled);
    setOnboardingToggleBusy(true);
    try {
      const updatePayload = {
        onboardingEnabled: nextEnabled,
      };
      if (nextEnabled && !selectedTank?.onboardingStartAt) {
        updatePayload.onboardingStartAt = new Date();
        updatePayload.onboardingTaskChecks = {};
      }

      await updateDocWithTelemetry(
        'tanks',
        doc(db, 'tanks', selectedTank.id),
        buildTankUpdatePayload(selectedTank, updatePayload),
        {
          userId: user.uid,
          tankId: selectedTank.id,
          source: 'set_tank_onboarding_enabled',
        }
      );

      setTanks((prev) =>
        prev.map((tank) =>
          tank.id === selectedTank.id
            ? {
                ...tank,
                onboardingEnabled: nextEnabled,
                ...(nextEnabled && !tank?.onboardingStartAt
                  ? { onboardingStartAt: new Date(), onboardingTaskChecks: {} }
                  : {}),
              }
            : tank
        )
      );
      setSelectedTank((prev) =>
        !prev
          ? prev
          : {
              ...prev,
              onboardingEnabled: nextEnabled,
              ...(nextEnabled && !prev?.onboardingStartAt
                ? { onboardingStartAt: new Date(), onboardingTaskChecks: {} }
                : {}),
            }
      );
      alert(nextEnabled ? "Onboarding włączony." : "Onboarding wyłączony.");
    } catch (error) {
      alert(
        "Błąd zmiany statusu onboardingu: " +
          (error instanceof Error ? error.message : '')
      );
    } finally {
      setOnboardingToggleBusy(false);
    }
  };

  const handleUpdateMaintenanceActionState = useCallback(
    async (action, mode) => {
      if (
        !selectedTank?.id ||
        !user?.uid ||
        !action?.stateKey ||
        !mode ||
        maintenanceActionBusyId
      ) {
        return;
      }

      const actionStateKey = String(action.stateKey ?? '').trim().toLowerCase();
      if (!actionStateKey) {
        return;
      }

      const actionBusyId = `${actionStateKey}-${String(mode ?? '')}`;
      setMaintenanceActionBusyId(actionBusyId);

      try {
        const latestMeasurementDayBucketMs = getDayBucketMs(
          getMeasurementRecordedAtMs(measurements?.[0])
        );
        const nextStatePayload = buildNextMaintenanceActionState({
          currentState: selectedTank?.maintenanceActionState,
          action,
          mode,
          latestMeasurementDayBucketMs,
        });
        if (!nextStatePayload) {
          return;
        }
        const nextState = nextStatePayload.nextState;

        await updateDocWithTelemetry(
          'tanks',
          doc(db, 'tanks', selectedTank.id),
          buildTankUpdatePayload(selectedTank, {
            maintenanceActionState: nextState,
          }),
          {
            userId: user.uid,
            tankId: selectedTank.id,
            source: 'update_maintenance_action_state',
          }
        );

        setTanks((prev) =>
          prev.map((tank) =>
            tank.id === selectedTank.id
              ? { ...tank, maintenanceActionState: nextState }
              : tank
          )
        );
        setSelectedTank({
          ...selectedTank,
          maintenanceActionState: nextState,
        });
      } catch (error) {
        alert(
          "Błąd zapisu akcji kalendarza: " +
            (error instanceof Error ? error.message : '')
        );
      } finally {
        setMaintenanceActionBusyId('');
      }
    },
    [
      maintenanceActionBusyId,
      measurements,
      selectedTank,
      setSelectedTank,
      setTanks,
      user?.uid,
      setMaintenanceActionBusyId,
    ]
  );

  const toggleDiseaseSymptom = (symptomId) => {
    setSelectedDiseaseSymptoms((prev) => ({
      ...prev,
      [symptomId]: !prev[symptomId],
    }));
  };

  const togglePlantDiseaseSymptom = (symptomId) => {
    setSelectedPlantDiseaseSymptoms((prev) => ({
      ...prev,
      [symptomId]: !prev[symptomId],
    }));
  };

  const toggleAlgaeSymptom = (symptomId) => {
    setSelectedAlgaeSymptoms((prev) => ({
      ...prev,
      [symptomId]: !prev[symptomId],
    }));
  };

  const handleCloseIssueTankPicker = useCallback(() => {
    setIsIssueTankPickerVisible(false);
    setIssueTankPickerPayload(null);
  }, []);

  const handleAssignCatalogFishToTank = async (fish, tank) => {
    if (!user?.uid || !tank?.id) {
      return;
    }
    if (stockBusy) {
      alert("Trwa zapisywanie poprzedniej zmiany. Spróbuj ponownie za chwilę.");
      return;
    }

    setStockBusy(true);

    try {
      const selectedFish = fishCatalog.find((item) => item.id === fish?.id) ?? fish;
      if (!selectedFish?.id) {
        throw new Error('Wybrana ryba nie istnieje w katalogu.');
      }

      const sanitizedFish = getSanitizedFishCatalogFields(selectedFish);
      const schoolingProfile = resolveFishSchoolingProfile(selectedFish);
      const aggressionLevel = resolveFishAggressionLevel(selectedFish);
      const quantity = 1;
      const minLiters = sanitizedFish.minLiters;
      const fishProfile = buildFishSpeciesProfile(
        {
          ...selectedFish,
          ...sanitizedFish,
          aggressionLevel,
          isSchooling: schoolingProfile.isSchooling,
          minGroupSize: schoolingProfile.minGroupSize,
        },
        quantity
      );
      const newFishCandidate = {
        type: 'fish',
        speciesId: selectedFish.id,
        name: sanitizedFish.commonName,
        commonName: sanitizedFish.commonName,
        latinName: sanitizedFish.latinName,
        quantity,
        sexRatio: 'unknown',
        lifeStage: 'unknown',
        aggressionLevel,
        fishProfile,
        notes: String(selectedFish.notes ?? '').slice(0, 1000),
      };
      const stockSnapshot = await getDocs(
        query(collection(db, 'stockItems'), where('userId', '==', user.uid))
      );
      const existingTankFishItems = stockSnapshot.docs
        .map((item) => ({
          id: item.id,
          ...item.data(),
        }))
        .filter(
          (item) =>
            item?.tankId === tank.id &&
            String(item?.type ?? '').toLowerCase() === 'fish'
        );

      const fishPayload = {
        userId: user.uid,
        tankId: tank.id,
        tankName: tank.name,
        type: 'fish',
        name: sanitizedFish.commonName,
        commonName: sanitizedFish.commonName,
        latinName: sanitizedFish.latinName,
        catalogFishId: getFishCatalogEntryId(selectedFish),
        phMin: sanitizedFish.phMin,
        phMax: sanitizedFish.phMax,
        ghMin: sanitizedFish.ghMin,
        ghMax: sanitizedFish.ghMax,
        tempMin: sanitizedFish.tempMin,
        tempMax: sanitizedFish.tempMax,
        quantity,
        minLiters,
        isSchooling: schoolingProfile.isSchooling,
        minGroupSize: schoolingProfile.isSchooling
          ? Math.max(1, Number(schoolingProfile.minGroupSize) || 1)
          : 1,
        aggressionLevel,
        fishProfile,
        notes: String(selectedFish.notes ?? '').slice(0, 1000),
        createdAt: new Date(),
      };
      const normalizedFishPayload = buildStockItemWritePayload(fishPayload, {
        mode: 'create',
        includeCreatedAtIfMissing: true,
        includeUpdatedAt: false,
      });
      const fishPayloadValidation = validateStockItemModelRuntime(normalizedFishPayload);
      if (!fishPayloadValidation.ok) {
        throw new Error(
          `Nieprawidlowy payload obsady (fish): ${fishPayloadValidation.issues.join(', ')}`
        );
      }
      try {
        await addDocWithTelemetry(
          'stockItems',
          collection(db, 'stockItems'),
          normalizedFishPayload,
          {
            userId: user.uid,
            tankId: tank.id,
            source: 'assign_catalog_fish_to_tank',
          }
        );
      } catch (error) {
        if (!isFirestorePermissionDeniedError(error)) {
          throw error;
        }

        const legacyPayload = { ...fishPayload };
        delete legacyPayload.fishProfile;
        delete legacyPayload.source;
        const normalizedLegacyFishPayload = buildStockItemWritePayload(legacyPayload, {
          mode: 'create',
          includeCreatedAtIfMissing: true,
          includeUpdatedAt: false,
        });
        const legacyPayloadValidation = validateStockItemModelRuntime(
          normalizedLegacyFishPayload
        );
        if (!legacyPayloadValidation.ok) {
          throw new Error(
            `Nieprawidlowy payload obsady (fish-legacy): ${legacyPayloadValidation.issues.join(', ')}`
          );
        }
        await addDocWithTelemetry(
          'stockItems',
          collection(db, 'stockItems'),
          normalizedLegacyFishPayload,
          {
            userId: user.uid,
            tankId: tank.id,
            source: 'assign_catalog_fish_to_tank_compatibility',
          }
        );
      }

      if (selectedTank?.id === tank.id) {
        await fetchStockItems(user.uid, tank.id);
      }
      await fetchHomeData(user.uid);

      const addWarnings = [];
      if (schoolingProfile.isSchooling && quantity < Number(schoolingProfile.minGroupSize)) {
        addWarnings.push(
          t('schoolingFishWarning', {
            value: schoolingProfile.minGroupSize,
          })
        );
      }

      const pairConflicts = existingTankFishItems
        .map((item) => ({
          item,
          conflict: getFishAggressionConflict(
            newFishCandidate,
            item,
            Number(tank?.liters)
          ),
        }))
        .filter((entry) => entry.conflict);
      if (pairConflicts.length > 0) {
        const worstConflict = [...pairConflicts].sort(
          (a, b) => Number(a.conflict?.score ?? 100) - Number(b.conflict?.score ?? 100)
        )[0];
        const otherFishName =
          worstConflict?.item?.commonName ??
          worstConflict?.item?.name ??
          worstConflict?.item?.latinName ??
          'inna ryba';
        const reasons = (worstConflict?.conflict?.reasons ?? []).slice(0, 2);
        const levelLabel = String(worstConflict?.conflict?.label ?? 'ryzykowne');
        addWarnings.push(
          `Konflikt obsady (${levelLabel}): ${newFishCandidate.commonName} + ${otherFishName}.`
        );
        if (reasons.length > 0) {
          addWarnings.push(`Powody: ${reasons.join(' ')}`);
        }
      }
      const dynamicAssessment = evaluateStockingCompatibility(
        tank,
        [...existingTankFishItems, newFishCandidate],
        null
      );
      if (['caution', 'high_risk', 'incompatible'].includes(dynamicAssessment.overallStatus)) {
        addWarnings.push(
          `Wplyw na obsade: ${dynamicAssessment.overallUiStatus} (${dynamicAssessment.score}%).`
        );
        const topWarnings = (dynamicAssessment.warnings ?? []).slice(0, 2);
        if (topWarnings.length > 0) {
          addWarnings.push(`Powody: ${topWarnings.join(' ')}`);
        }
        const topRecommendations = (dynamicAssessment.recommendations ?? []).slice(0, 1);
        if (topRecommendations.length > 0) {
          addWarnings.push(`Rekomendacja: ${topRecommendations[0]}`);
        }
      }

      if (Number(tank?.liters) < minLiters) {
        addWarnings.push(
          "Uwaga: minimalny litraż tej ryby jest większy niż litraż wybranego akwarium."
        );
      }

      if (addWarnings.length === 0) {
        alert(`Dodano do akwarium "${tank.name}".`);
      } else {
        alert(`Dodano do akwarium "${tank.name}".\n\n${addWarnings.join('\n')}`);
      }
    } catch (error) {
      alert(
        "Błąd dodawania ryby do akwarium: " +
          (error instanceof Error ? error.message : '')
      );
    } finally {
      setStockBusy(false);
    }
  };

  const handleUpdatePlantQuantity = async (itemId) => {
    if (!user || !selectedTank?.id || stockBusy) {
      return false;
    }

    setStockBusy(true);

    try {
      const draft = plantQuantityDrafts[itemId] ?? '';
      const quantity = parseNonNegativeNumberOrThrow("ilość", String(draft));

      if (!Number.isInteger(quantity)) {
        throw new Error("Pole ilość musi byc liczba calkowita");
      }

      if (quantity === 0) {
        await deleteDoc(doc(db, 'stockItems', itemId));
      } else {
        await updateDocWithTelemetry(
          'stockItems',
          doc(db, 'stockItems', itemId),
          buildStockItemWritePayload(
            { quantity },
            { mode: 'update', includeUpdatedAt: false }
          ),
          {
            userId: user.uid,
            tankId: selectedTank.id,
            source: 'update_stock_item_plant_quantity',
          }
        );
      }
      await fetchStockItems(user.uid, selectedTank.id);

      alert(
        quantity === 0
          ? "Roślina usunięta z obsady (ilość ustawiona na 0)."
          : "Ilość rośliny zaktualizowana"
      );
      return true;
    } catch (error) {
      alert(
        "Błąd aktualizacji ilosci: " +
          (error instanceof Error ? error.message : '')
      );
      return false;
    } finally {
      setStockBusy(false);
    }
  };

  const handleAssignCatalogPlantToTank = async (plant, tank) => {
    if (!user?.uid || !tank?.id) {
      return;
    }
    if (stockBusy) {
      alert("Trwa zapisywanie poprzedniej zmiany. Spróbuj ponownie za chwilę.");
      return;
    }

    setStockBusy(true);

    try {
      const selectedPlant = plantCatalog.find((item) => item.id === plant?.id) ?? plant;
      if (!selectedPlant?.id) {
        throw new Error("Wybrana roślina nie istnieje w katalogu.");
      }

      const sanitizedPlant = getSanitizedPlantCatalogFields(selectedPlant);
      const minLiters = sanitizedPlant.minLiters;
      const lightRequirements = getPlantLightRequirements({
        ...selectedPlant,
        ...sanitizedPlant,
      });
      const requirementsProfile = inferPlantRequirementProfile({
        ...selectedPlant,
        ...sanitizedPlant,
        minLiters,
      });

      const plantPayload = buildStockItemWritePayload(
        {
          userId: user.uid,
          tankId: tank.id,
          tankName: tank.name,
          type: 'plant',
          name: sanitizedPlant.commonName,
          commonName: sanitizedPlant.commonName,
          latinName: sanitizedPlant.latinName,
          catalogPlantId: selectedPlant.id,
          phMin: sanitizedPlant.phMin,
          phMax: sanitizedPlant.phMax,
          ghMin: sanitizedPlant.ghMin,
          ghMax: sanitizedPlant.ghMax,
          tempMin: sanitizedPlant.tempMin,
          tempMax: sanitizedPlant.tempMax,
          quantity: 1,
          minLiters,
          lightLumenMinPerLiter: Number(lightRequirements.minLumensPerLiter),
          lightLumenMaxPerLiter: Number(lightRequirements.maxLumensPerLiter),
          lightHoursMin: Number.isFinite(Number(lightRequirements.minHours))
            ? Number(lightRequirements.minHours)
            : null,
          lightHoursMax: Number.isFinite(Number(lightRequirements.maxHours))
            ? Number(lightRequirements.maxHours)
            : null,
          lightDemand: requirementsProfile.lightDemand,
          co2Demand: requirementsProfile.co2Demand,
          growthRate: requirementsProfile.growthRate,
          difficulty: requirementsProfile.difficulty,
          fertilizationDemand: requirementsProfile.fertilizationDemand,
          plantType: requirementsProfile.plantType,
          placementZone: requirementsProfile.placementZone,
          carboSensitivity: requirementsProfile.carboSensitivity,
          parameterStabilitySensitivity:
            requirementsProfile.parameterStabilitySensitivity,
          minTankHeightCm: requirementsProfile.minTankHeightCm,
          minTankVolumeL: requirementsProfile.minTankVolumeL,
          compatibleWithDiggers: requirementsProfile.compatibleWithDiggers,
          notes: String(selectedPlant.notes ?? '').trim(),
          createdAt: new Date(),
        },
        {
          mode: 'create',
          includeCreatedAtIfMissing: true,
          includeUpdatedAt: false,
        }
      );
      const plantPayloadValidation = validateStockItemModelRuntime(plantPayload);
      if (!plantPayloadValidation.ok) {
        throw new Error(
          `Nieprawidlowy payload obsady (plant): ${plantPayloadValidation.issues.join(', ')}`
        );
      }
      await addDocWithTelemetry(
        'stockItems',
        collection(db, 'stockItems'),
        plantPayload,
        {
          userId: user.uid,
          tankId: tank.id,
          source: 'assign_catalog_plant_to_tank',
        }
      );

      if (selectedTank?.id === tank.id) {
        await fetchStockItems(user.uid, tank.id);
      }
      await fetchHomeData(user.uid);

      const addWarnings = [];
      if (Number(tank?.liters) < minLiters) {
        addWarnings.push(
          "Uwaga: minimalny litraż tej rośliny jest większy niż litraż wybranego akwarium."
        );
      }

      if (addWarnings.length === 0) {
        alert(`Dodano do akwarium "${tank.name}".`);
      } else {
        alert(`Dodano do akwarium "${tank.name}".\n\n${addWarnings.join('\n')}`);
      }
    } catch (error) {
      alert(
        "Błąd dodawania rośliny do akwarium: " +
          (error instanceof Error ? error.message : '')
      );
    } finally {
      setStockBusy(false);
    }
  };

  const handleSelectIssueTank = async (tank) => {
    if (!tank?.id || !issueTankPickerPayload) {
      return;
    }

    const { kind, item } = issueTankPickerPayload;
    setIsIssueTankPickerVisible(false);
    setIssueTankPickerPayload(null);

    if (kind === 'disease') {
      await handleAssignDiseaseToTank(item, tank);
      return;
    }

    if (kind === 'plant_disease') {
      await handleAssignPlantDiseaseToTank(item, tank);
      return;
    }

    if (kind === 'algae') {
      await handleAssignAlgaeToTank(item, tank);
      return;
    }

    if (kind === 'fish_catalog') {
      await handleAssignCatalogFishToTank(item, tank);
      return;
    }

    if (kind === 'plant_catalog') {
      await handleAssignCatalogPlantToTank(item, tank);
    }
  };

  const handleOpenIssueTankPicker = (kind, item) => {
    if (!user?.uid || !item) {
      return;
    }

    if (tanks.length === 0) {
      alert('Najpierw dodaj akwarium.');
      return;
    }

    if (tanks.length === 1) {
      const onlyTank = tanks[0];
      if (kind === 'disease') {
        handleAssignDiseaseToTank(item, onlyTank);
        return;
      }
      if (kind === 'plant_disease') {
        handleAssignPlantDiseaseToTank(item, onlyTank);
        return;
      }
      if (kind === 'algae') {
        handleAssignAlgaeToTank(item, onlyTank);
        return;
      }
      if (kind === 'fish_catalog') {
        handleAssignCatalogFishToTank(item, onlyTank);
        return;
      }
      if (kind === 'plant_catalog') {
        handleAssignCatalogPlantToTank(item, onlyTank);
      }
      return;
    }

    setIssueTankPickerPayload({ kind, item });
    setIsIssueTankPickerVisible(true);
  };

  const resolveCatalogAiContextTank = () => {
    const preferredTankId = String(
      catalogAiContextTankId || selectedTank?.id || tanks[0]?.id || ''
    ).trim();
    if (!preferredTankId) {
      return null;
    }
    return tanks.find((tankItem) => String(tankItem?.id ?? '') === preferredTankId) ?? null;
  };

  const buildCatalogAiContextSummary = async (tankOverride = null) => {
    if (!user?.uid) {
      return '';
    }
    const tank = tankOverride ?? resolveCatalogAiContextTank();
    if (!tank?.id) {
      return '';
    }

    const snapshot = await getDocs(
      query(collection(db, 'measurements'), where('userId', '==', user.uid))
    );
    const latestMeasurement = normalizeArray(snapshot?.docs)
      .map((item) => ({
        id: normalizeString(item?.id),
        ...normalizeMeasurementRuntime(normalizeObject(item?.data?.())),
      }))
      .filter(
        (item) =>
          Boolean(item?.id) && String(item?.tankId ?? '') === String(tank.id)
      )
      .sort((left, right) => getMeasurementRecordedAtMs(right) - getMeasurementRecordedAtMs(left))[0];

    const summaryParts = [
      `Akwarium: ${String(tank?.name ?? 'Akwarium').trim()}`,
      Number.isFinite(Number(tank?.liters)) ? `Litraż: ${Math.round(Number(tank.liters))} l` : '',
      String(tank?.waterProfile ?? '').trim()
        ? `Profil: ${String(tank.waterProfile).trim()}`
        : '',
      latestMeasurement
        ? `Ostatni pomiar: pH ${latestMeasurement.ph ?? '-'}, NO2 ${latestMeasurement.no2 ?? '-'}, NO3 ${latestMeasurement.no3 ?? '-'}, temp ${latestMeasurement.temperature ?? '-'}`
        : "Brak pomiarów dla tego akwarium.",
    ].filter(Boolean);

    return summaryParts.join('. ');
  };

  const handleHydrateCatalogAiContextFromTank = async (tankId) => {
    const normalizedTankId = String(tankId ?? '').trim();
    const tank =
      tanks.find((tankItem) => String(tankItem?.id ?? '') === normalizedTankId) ?? null;
    if (!tank?.id) {
      setCatalogAiError('Wybierz akwarium, aby pobrac parametry do kontekstu AI.');
      return;
    }

    setCatalogAiBusy(true);
    setCatalogAiError('');
    try {
      const contextSummary = await buildCatalogAiContextSummary(tank);
      setCatalogAiContextTankId(tank.id);
      setCatalogAiContextSummary(contextSummary);
      if (!contextSummary) {
        setCatalogAiError("Nie udało się zbudować kontekstu. Sprawdź dane akwarium.");
      }
    } catch (error) {
      setCatalogAiError(
        "Błąd pobierania parametrów z akwarium: " +
          (error instanceof Error ? error.message : '')
      );
    } finally {
      setCatalogAiBusy(false);
    }
  };

  const runCatalogAiChat = async ({
    resultKey,
    question,
    contextDetails = '',
    tankId = null,
  }) => {
    if (!hasAiAssistantAccess) {
      setCatalogAiError(t('aiAssistantLockedPro'));
      return;
    }
    if (!appSettings.aiConsentDataProcessing) {
      setCatalogAiError("Włącz zgodę na przetwarzanie danych AI, aby uruchomić analizę.");
      return;
    }
    if (!user?.getIdToken) {
      setCatalogAiError("Brak aktywnej sesji. Zaloguj się ponownie.");
      return;
    }

    setCatalogAiBusy(true);
    setCatalogAiError('');
    try {
      const contextTank = resolveCatalogAiContextTank();
      const fallbackContext = await buildCatalogAiContextSummary(contextTank);
      const contextFromTank = catalogAiContextSummary || fallbackContext;
      const userProblem = String(catalogAiProblemInput ?? '').trim().slice(0, 500);
      const effectiveQuestion = userProblem
        ? `${String(question ?? '').trim()}\nUwzglednij dodatkowy problem użytkownika: ${userProblem}`
        : String(question ?? '').trim();
      const additionalInfo = [contextFromTank, contextDetails]
        .map((value) => String(value ?? '').trim())
        .filter(Boolean)
        .join('\n');
      const idToken = await user.getIdToken();
      const response = await requestAiChat({
        idToken: String(idToken ?? ''),
        question: effectiveQuestion,
        additionalInfo,
        tankId: String(tankId || contextTank?.id || '').trim() || null,
      });

      setCatalogAiResultByKey((prev) => ({
        ...prev,
        [resultKey]: {
          mode: 'chat',
          answer: String(response?.answer ?? '').trim(),
          recommendations: Array.isArray(response?.recommendations)
            ? response.recommendations.slice(0, 4)
            : [],
          warnings: Array.isArray(response?.warnings) ? response.warnings.slice(0, 3) : [],
          atLabel: new Date().toLocaleString(),
        },
      }));
    } catch (rawError) {
      const mappedError =
        rawError instanceof AiChatRequestError
          ? rawError
          : new AiChatRequestError(
              "Błąd analizy AI w katalogu. Spróbuj ponownie.",
              'AIW_INTERNAL',
              true
            );
      setCatalogAiError(mappedError.message);
    } finally {
      setCatalogAiBusy(false);
    }
  };

  const handlePickCatalogAiImage = async (source) => {
    if (!hasAiAssistantAccess) {
      setCatalogAiError(t('aiAssistantLockedPro'));
      return;
    }
    if (!appSettings.aiConsentDataProcessing || !appSettings.aiConsentImageAnalysis) {
      setCatalogAiError(
        "Aby analizowac zdjęcia, włącz zgody: przetwarzanie danych AI i analiza obrazow."
      );
      return;
    }

    setCatalogAiBusy(true);
    setCatalogAiError('');
    try {
      const picked = await pickVisionImage(source);
      if (!picked?.uri) {
        return;
      }
      setCatalogAiSelectedImage({
        uri: String(picked.uri),
        width: Number(picked.width) || 0,
        height: Number(picked.height) || 0,
        mimeType: String(picked.mimeType || 'image/jpeg'),
      });
    } catch (rawError) {
      const mappedError =
        rawError instanceof AiChatRequestError
          ? rawError
          : new AiChatRequestError(
              "Nie udało się wybrać zdjęcia. Spróbuj ponownie.",
              'AIW_INTERNAL',
              true
            );
      setCatalogAiError(mappedError.message);
    } finally {
      setCatalogAiBusy(false);
    }
  };

  const runCatalogAiVision = async ({
    resultKey,
    question,
    contextDetails = '',
    tankId = null,
  }) => {
    if (!hasAiAssistantAccess) {
      setCatalogAiError(t('aiAssistantLockedPro'));
      return;
    }
    if (!appSettings.aiConsentDataProcessing || !appSettings.aiConsentImageAnalysis) {
      setCatalogAiError(
        "Aby analizowac zdjęcia, włącz zgody: przetwarzanie danych AI i analiza obrazow."
      );
      return;
    }
    if (!user?.uid || !user?.getIdToken) {
      setCatalogAiError("Brak aktywnej sesji. Zaloguj się ponownie.");
      return;
    }
    if (!catalogAiSelectedImage?.uri) {
      setCatalogAiError("Dodaj zdjęcie z aparatu lub galerii przed analiza.");
      return;
    }

    setCatalogAiBusy(true);
    setCatalogAiError('');
    try {
      const contextTank = resolveCatalogAiContextTank();
      const fallbackContext = await buildCatalogAiContextSummary(contextTank);
      const contextFromTank = catalogAiContextSummary || fallbackContext;
      const userProblem = String(catalogAiProblemInput ?? '').trim().slice(0, 500);
      const effectiveQuestion = userProblem
        ? `${String(question ?? '').trim()}\nUwzglednij dodatkowy problem użytkownika: ${userProblem}`
        : String(question ?? '').trim();
      const additionalInfo = [contextFromTank, contextDetails]
        .map((value) => String(value ?? '').trim())
        .filter(Boolean)
        .join('\n');
      const idToken = await user.getIdToken();
      const uploaded = await uploadVisionImageForUserBestEffort(String(user.uid), catalogAiSelectedImage);
      const response = await requestAiVisionAnalyzeWithRetry(
        {
          idToken: String(idToken ?? ''),
          imageUrl: uploaded?.downloadUrl || '',
          imageBase64: catalogAiSelectedImage.base64,
          imageMimeType: catalogAiSelectedImage.mimeType,
          question: effectiveQuestion,
          additionalInfo,
          tankId: String(tankId || contextTank?.id || '').trim() || null,
        },
        { maxAttempts: 2, retryDelayMs: 450 }
      );

      setCatalogAiResultByKey((prev) => ({
        ...prev,
        [resultKey]: {
          mode: 'vision',
          answer: String(response?.summary ?? '').trim(),
          summary: String(response?.summary ?? '').trim(),
          recommendations: Array.isArray(response?.recommendations)
            ? response.recommendations.slice(0, 4)
            : [],
          warnings: Array.isArray(response?.warnings) ? response.warnings.slice(0, 3) : [],
          hypotheses: Array.isArray(response?.hypotheses) ? response.hypotheses.slice(0, 3) : [],
          verificationSteps: Array.isArray(response?.verificationSteps)
            ? response.verificationSteps.slice(0, 3)
            : [],
          actionPlan: Array.isArray(response?.actionPlan) ? response.actionPlan.slice(0, 4) : [],
          unreadableImageFallback: Boolean(response?.unreadableImageFallback),
          imageUri: String(catalogAiSelectedImage?.uri ?? ''),
          atLabel: new Date().toLocaleString(),
        },
      }));
    } catch (rawError) {
      const mappedError =
        rawError instanceof AiChatRequestError
          ? rawError
          : new AiChatRequestError(
              "Błąd analizy AI w katalogu. Spróbuj ponownie.",
              'AIW_INTERNAL',
              true
            );
      setCatalogAiError(mappedError.message);
    } finally {
      setCatalogAiBusy(false);
    }
  };

  const buildWaterHistoryAiPayload = (tank) => {
      const tankId = String(tank?.id ?? '').trim();
      const measurementValueKeys = [
        'ph',
        'gh',
        'kh',
        'no2',
        'no3',
        'nh3nh4',
        'temperature',
        'po4',
        'fe',
        'ca',
        'mg',
        'k',
        'tds',
        'co2',
      ];
      const toMeasurementNumber = (value) => {
        const numeric = Number(value);
        return Number.isFinite(numeric) ? numeric : null;
      };
      const hasMeasurementData = (item) =>
        measurementValueKeys.some((key) => toMeasurementNumber(item?.[key]) !== null);
      const mapMeasurementForAi = (item) => {
        const mapped = {
          measuredAt: item?.measuredAt ?? item?.createdAt ?? null,
        };
        measurementValueKeys.forEach((key) => {
          mapped[key] = toMeasurementNumber(item?.[key]);
        });
        return mapped;
      };
      const buildLatestMeasurementForAi = (items) => {
        const snapshot = { measuredAt: null };
        const valueSources = {};
        measurementValueKeys.forEach((key) => {
          const source = items.find((item) => toMeasurementNumber(item?.[key]) !== null);
          snapshot[key] = source ? toMeasurementNumber(source?.[key]) : null;
          if (source) {
            const measuredAt = source?.measuredAt ?? source?.createdAt ?? null;
            valueSources[key] = measuredAt;
            if (!snapshot.measuredAt) {
              snapshot.measuredAt = measuredAt;
            }
          }
        });
        return Object.keys(valueSources).length > 0
          ? {
              ...snapshot,
              valueSources,
            }
          : null;
      };
      const tankMeasurements = normalizeArray(measurements)
        .filter((item) => String(item?.tankId ?? '').trim() === tankId)
        .sort((left, right) => getMeasurementRecordedAtMs(right) - getMeasurementRecordedAtMs(left));
      const usefulTankMeasurements = tankMeasurements.filter(hasMeasurementData);
      const latestMeasurement = buildLatestMeasurementForAi(usefulTankMeasurements);
      const measurementHistory = usefulTankMeasurements.slice(0, 8).map(mapMeasurementForAi);

      const timelineEvents = normalizeArray(historyIssueTimeline).map((item) => ({
        at:
          item?.startedAtIso ??
          item?.endedAtIso ??
          item?.updatedAtIso ??
          item?.createdAtIso ??
          null,
        type: item?.type ?? item?.caseType ?? 'issue',
        label: item?.issueName ?? item?.title ?? item?.name ?? 'Zdarzenie',
        status: item?.status ?? null,
      }));

      const diseaseCaseEvents = normalizeArray(tankDiseaseHistoryCases)
        .filter((item) => String(item?.tankId ?? '').trim() === tankId)
        .map((item) => ({
          at: item?.updatedAt ?? item?.resolvedAt ?? item?.createdAt ?? null,
          type: item?.caseType ?? 'issue_case',
          label:
            item?.issueName ??
            item?.diseaseType ??
            item?.name ??
            'Przypadek historii',
          status: item?.status ?? null,
        }));

      const recentEvents = [...timelineEvents, ...diseaseCaseEvents]
        .sort((left, right) => getCreatedAtMs(right?.at) - getCreatedAtMs(left?.at))
        .slice(0, 8)
        .map((item) => ({
          at: item?.at ?? null,
          type: item?.type ?? 'event',
          label: item?.label ?? 'Zdarzenie',
          status: item?.status ?? null,
        }));

      const latestMeasurementRecordedAtMs = getMeasurementRecordedAtMs(latestMeasurement);
      const latestMeasurementAgeDays = latestMeasurementRecordedAtMs
        ? Math.max(0, Math.floor((Date.now() - latestMeasurementRecordedAtMs) / (24 * 60 * 60 * 1000)))
        : null;

      const payload = {
        aquarium: {
          name: String(tank?.name ?? '').trim() || 'Akwarium',
          liters: Number.isFinite(Number(tank?.liters)) ? Number(tank.liters) : null,
          type: String(tank?.aquariumType ?? '').trim() || null,
          startType: String(tank?.startType ?? '').trim() || null,
          targetTemperatureC:
            Number.isFinite(Number(tank?.targetTemperatureC)) ? Number(tank.targetTemperatureC) : null,
          ambientTemperatureC:
            Number.isFinite(Number(tank?.ambientTemperatureC)) ? Number(tank.ambientTemperatureC) : null,
          stockSummary: {
            fishCount: fishInTank.length,
            plantCount: plantsInTank.length,
          },
          filtrationSummary: {
            status: String(currentEquipmentAssessmentForContext?.filters?.status ?? '').trim() || null,
            requiredFlowLh:
              Number.isFinite(Number(currentEquipmentAssessmentForContext?.filters?.requiredFlowLh))
                ? Number(currentEquipmentAssessmentForContext.filters.requiredFlowLh)
                : null,
            realFlowLh:
              Number.isFinite(Number(currentEquipmentAssessmentForContext?.filters?.actualRealFlowLh))
                ? Number(currentEquipmentAssessmentForContext.filters.actualRealFlowLh)
                : null,
          },
        },
        latestMeasurement,
        measurementHistory,
        recentEvents,
        analysisMeta: {
          measurementCount: usefulTankMeasurements.length,
          rawMeasurementCount: tankMeasurements.length,
          latestMeasurementAgeDays,
          hasTrendData: usefulTankMeasurements.length >= 2,
        },
      };

      const payloadJson = JSON.stringify(payload);
      if (payloadJson.length <= 3600) {
        return payloadJson;
      }

      const reducedPayload = {
        ...payload,
        measurementHistory: measurementHistory.slice(0, 5),
        recentEvents: recentEvents.slice(0, 5),
      };
      const reducedJson = JSON.stringify(reducedPayload);
      if (reducedJson.length <= 3600) {
        return reducedJson;
      }
      return JSON.stringify({
        ...reducedPayload,
        measurementHistory: measurementHistory.slice(0, 3),
        recentEvents: recentEvents.slice(0, 3),
      });
    };

  const handleAnalyzeWaterHistoryWithAi = async () => {
    if (historyAiBusy) {
      return;
    }
    if (!hasAiAssistantAccess) {
      alert(
        aiAssistantUpgradePromptMessage ||
          aiAssistantLockMessage ||
          t('aiAssistantLockedPro')
      );
      return;
    }
    if (!appSettings.aiConsentDataProcessing) {
      setHistoryAiError(t('historyAiErrorConsentRequired'));
      return;
    }
    if (!user?.getIdToken) {
      setHistoryAiError(t('historyAiErrorSessionExpired'));
      return;
    }

    const tank = selectedTank ?? tanks[0] ?? null;
    if (!tank?.id) {
      setHistoryAiError(t('historyAiErrorNoTank'));
      return;
    }

    setHistoryAiBusy(true);
    setHistoryAiError('');
    const startedAt = Date.now();

    const question = t('historyAiQuestionPrompt');
    const additionalInfo = buildWaterHistoryAiPayload(tank);
    const tankId = String(tank.id);

    trackAiRequestStarted({
      operation: 'chat',
      source: 'history_measurements_section',
      hasTankId: true,
      questionLength: String(question ?? '').length,
      additionalInfoLength: String(additionalInfo ?? '').length,
    });

    try {
      const idToken = await user.getIdToken();
      const response = await requestAiChat({
        idToken: String(idToken ?? ''),
        question,
        additionalInfo,
        tankId,
        mode: 'water_history_analysis',
        userLanguage: appSettings.language,
        appLanguage: appSettings.language,
        locale: appSettings.language,
      });

      setHistoryAiResult({
        answer: String(response?.answer ?? '').trim(),
        recommendations: normalizeArray(response?.recommendations).slice(0, 4),
        warnings: normalizeArray(response?.warnings).slice(0, 4),
      });
      setHistoryAiAtLabel(new Date().toLocaleString());

      trackAiRequestSuccess({
        operation: 'chat',
        source: 'history_measurements_section',
        durationMs: Date.now() - startedAt,
        diagnosticCode: response?.diagnosticCode ?? 'AIW_OK',
        hasTankId: true,
      });
    } catch (rawError) {
      const mappedError =
        rawError instanceof AiChatRequestError
          ? rawError
          : new AiChatRequestError(
              t('historyAiErrorUnexpected'),
              'AIW_INTERNAL',
              true
            );
      setHistoryAiError(mappedError.message || t('historyAiErrorUnexpected'));
      trackAiRequestFailure(mappedError, {
        operation: 'chat',
        source: 'history_measurements_section',
        durationMs: Date.now() - startedAt,
        diagnosticCode: mappedError.code ?? 'AIW_INTERNAL',
        httpStatus: mappedError.status ?? null,
        hasTankId: true,
        questionLength: String(question ?? '').length,
        additionalInfoLength: String(additionalInfo ?? '').length,
      });
    } finally {
      setHistoryAiBusy(false);
    }
  };

