  const handleAssignDiseaseToTank = async (disease, tank) => {
    if (!user?.uid || !tank || diseaseCaseBusy) {
      return;
    }

    setDiseaseCaseBusy(true);

    try {
      const schedule = buildDiseaseTreatmentSchedule(disease);
      const treatmentPlan =
        Array.isArray(disease?.treatmentPlan) && disease.treatmentPlan.length > 0
          ? disease.treatmentPlan.slice(0, 10)
          : (disease?.treatment ?? []).slice(0, 4);
      const probableCauses =
        Array.isArray(disease?.probableCauses) && disease.probableCauses.length > 0
          ? disease.probableCauses
          : [];
      const confidenceSuffix = Number.isFinite(Number(disease?.adjustedConfidencePercent))
        ? ` Pewnosc: ${Math.round(Number(disease.adjustedConfidencePercent))}% (${disease?.confidenceLevel ?? 'ocena orientacyjna'}).`
        : '';
      const nextReviewAt =
        schedule[1]?.dueAt ??
        (() => {
          const review = new Date();
          review.setDate(review.getDate() + 1);
          return review;
        })();

      const diseaseCasePayload = buildTankDiseaseCaseWritePayload(
        {
          userId: user.uid,
          tankId: tank.id,
          tankName: tank.name,
          caseType: 'disease',
          issueId: disease.id,
          issueName: disease.name,
          diseaseId: disease.id,
          diseaseName: disease.name,
          severity: disease.severity,
          diseaseSummary: `${disease.summary}${confidenceSuffix}`.slice(0, 3000),
          causes: probableCauses.slice(0, 30),
          caution: disease.caution,
          treatmentPlan,
          schedule,
          status: 'active',
          createdAt: new Date(),
          startedAt: new Date(),
          nextReviewAt,
        },
        {
          mode: 'create',
          includeCreatedAtIfMissing: true,
          includeUpdatedAt: false,
        }
      );
      const diseaseCaseValidation = validateTankDiseaseCaseModelRuntime(
        diseaseCasePayload
      );
      if (!diseaseCaseValidation.ok) {
        throw new Error(
          `Nieprawidlowy payload przypadku choroby: ${diseaseCaseValidation.issues.join(', ')}`
        );
      }
      await addDocWithTelemetry(
        'tankDiseaseCases',
        collection(db, 'tankDiseaseCases'),
        diseaseCasePayload,
        {
          userId: user.uid,
          tankId: tank.id,
          source: 'assign_disease_to_tank',
        }
      );

      if (selectedTank?.id === tank.id) {
        await fetchTankDiseaseCases(user.uid, tank.id);
      }

      alert(`Dodano do akwarium "${tank.name}". Szczegóły pojawily się w sekcji akwarium.`);
    } catch (error) {
      alert(
        "Błąd dodawania choroby do akwarium: " +
          (error instanceof Error ? error.message : '')
      );
    } finally {
      setDiseaseCaseBusy(false);
    }
  };

