                                  borderWidth: 1,
                                  borderColor: themeInputBorder,
                                  backgroundColor: themeInputBg,
                                  color: themeInputText,
                                  paddingHorizontal: 12,
                                  paddingVertical: 10,
                                  borderRadius: 10,
